var e=[{id:`L3_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`뭐야……?`,JPN:`なに……？`,ENG:`What…?`,TWN:`是怎樣……？`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`저 녀석……. 총 한 발에 갑자기 멈췄잖아?`,JPN:`あいつ……銃一発で動きが止まった？`,ENG:`That thing… All it took was a bullet to stop it?`,TWN:`那傢伙……突然因為一顆子彈就停下來？`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_DARK_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_DARK_NULL`,text:{KOREA:`컥…… 커헉……`,JPN:`ぐあ……ガハッ……`,ENG:`Ack… Hngh…`,TWN:`咳……咳咳……`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_DARK_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`역시…… 예상대로군요.`,JPN:`やはり……予想どおりですね。`,ENG:`Just as I expected…`,TWN:`果然……跟我想的一樣。`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`제 의지에 따라 강해진다면, 제 의지에 따라 파괴될 수도 있다는 뜻이겠죠.`,JPN:`僕の意志によって強くなるなら、僕の意志によって破壊されることもあるってことでしょう。`,ENG:`If it can grow strong from my resolve, that also means I could destroy it with my resolve.`,TWN:`如果他能夠照著我的意志變強，那我也就可以照著我的意志毀掉他。`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…….`,TWN:`……`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`이런 가벼운 총탄 하나에 핏물로 변해 버리다니…….`,JPN:`こんな普通の弾一発で血に変わってしまうなんて……`,ENG:`To think it only took a bullet to turn that thing to a puddle of blood…`,TWN:`竟然區區一顆子彈就把他變成一攤血……`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`비장의 무기로 쓰시기엔 약점이 너무 명확한 것 같네요.`,JPN:`切り札として使うには、弱点があまりにも明確なようですね。`,ENG:`It's got a gaping flaw to use as your ultimate weapon, don't you think?`,TWN:`說他是你的祕密武器未免也太弱？`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`다음엔 좀 더 신뢰성을 갖춘 괴물을 만드시는 편이 좋겠어요.`,JPN:`次はもう少し信頼性の高い化け物を作ったほうがいいんじゃないですか？`,ENG:`You should try to design a more reliable monster next time.`,TWN:`建議你下次可以做一些比較可靠的怪物。`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`아, 친절하게 가르쳐 주신 건 고마웠어요.`,JPN:`ああ、親切に教えてくださったのは助かりました。`,ENG:`Thanks for the tip though.`,TWN:`喔，還有，謝謝你剛剛親切的說明。`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`……이해할 수가 없군요.`,JPN:`……理解できません。`,ENG:`…I don't understand.`,TWN:`我不懂……`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`용인을 파괴해버리면 당신도, 당신의 부모도 구원받을 길이 없습니다.`,JPN:`龍人を破壊してしまうと、あなたも、あなたの両親も救われる手段が無くなるのですよ？`,ENG:`If you destroy the Dragonoid, neither you nor your parents can be redeemed.`,TWN:`毀掉龍人，不只是你，你的父母也無法得到救贖。`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`그런데 어째서…….`,JPN:`なのにどうして……`,ENG:`So why…`,TWN:`為什麼你……`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`……간단해요.`,JPN:`……簡単です。`,ENG:`…It's simple.`,TWN:`……答案很簡單。`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`전 귀가 밝은 편이거든요.`,JPN:`僕は地獄耳ですので。`,ENG:`I've got pretty good hearing.`,TWN:`因為我的耳朵很敏銳。`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…….`,TWN:`……`},stage:{bg:`MAINSTREAM_7090010`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`선배? 그 총은 뭐야?`,JPN:`先輩？　その銃はなに？`,ENG:`Shiyoon? What's with the gun?`,TWN:`前輩？怎麼會有那把槍？`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`방금 선배가 이 녀석을 쓰러트린 거야?`,JPN:`今先輩がこいつを倒したの？`,ENG:`Did you shoot that thing just now?`,TWN:`剛剛是前輩打中那傢伙嗎？`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};